#[repr(transparent)]
#[doc = " Specifies the pixel format of a texture.\n\n Texture format support varies depending on driver, hardware, and usage\n flags. In general, you should use SDL_GPUTextureSupportsFormat to query if\n a format is supported before using it. However, there are a few guaranteed\n formats.\n\n FIXME: Check universal support for 32-bit component formats FIXME: Check\n universal support for SIMULTANEOUS_READ_WRITE\n\n For SAMPLER usage, the following formats are universally supported:\n\n - R8G8B8A8_UNORM\n - B8G8R8A8_UNORM\n - R8_UNORM\n - R8_SNORM\n - R8G8_UNORM\n - R8G8_SNORM\n - R8G8B8A8_SNORM\n - R16_FLOAT\n - R16G16_FLOAT\n - R16G16B16A16_FLOAT\n - R32_FLOAT\n - R32G32_FLOAT\n - R32G32B32A32_FLOAT\n - R11G11B10_UFLOAT\n - R8G8B8A8_UNORM_SRGB\n - B8G8R8A8_UNORM_SRGB\n - D16_UNORM\n\n For COLOR_TARGET usage, the following formats are universally supported:\n\n - R8G8B8A8_UNORM\n - B8G8R8A8_UNORM\n - R8_UNORM\n - R16_FLOAT\n - R16G16_FLOAT\n - R16G16B16A16_FLOAT\n - R32_FLOAT\n - R32G32_FLOAT\n - R32G32B32A32_FLOAT\n - R8_UINT\n - R8G8_UINT\n - R8G8B8A8_UINT\n - R16_UINT\n - R16G16_UINT\n - R16G16B16A16_UINT\n - R8_INT\n - R8G8_INT\n - R8G8B8A8_INT\n - R16_INT\n - R16G16_INT\n - R16G16B16A16_INT\n - R8G8B8A8_UNORM_SRGB\n - B8G8R8A8_UNORM_SRGB\n\n For STORAGE usages, the following formats are universally supported:\n\n - R8G8B8A8_UNORM\n - R8G8B8A8_SNORM\n - R16G16B16A16_FLOAT\n - R32_FLOAT\n - R32G32_FLOAT\n - R32G32B32A32_FLOAT\n - R8G8B8A8_UINT\n - R16G16B16A16_UINT\n - R8G8B8A8_INT\n - R16G16B16A16_INT\n\n For DEPTH_STENCIL_TARGET usage, the following formats are universally\n supported:\n\n - D16_UNORM\n - Either (but not necessarily both!) D24_UNORM or D32_FLOAT\n - Either (but not necessarily both!) D24_UNORM_S8_UINT or D32_FLOAT_S8_UINT\n\n Unless D16_UNORM is sufficient for your purposes, always check which of\n D24/D32 is supported before creating a depth-stencil texture!\n\n **Available Since:** This enum is available since SDL 3.2.0.\n\n **See Also:** SDL_CreateGPUTexture\n **See Also:** SDL_GPUTextureSupportsFormat\n"]
#[derive(Debug, Copy, Clone, Hash, PartialEq, Eq)]
pub struct SDL_GPUTextureFormat(pub core::ffi::c_uint);
#[doc = " Specifies how a texture is intended to be used by the client.\n\n A texture must have at least one usage flag. Note that some usage flag\n combinations are invalid.\n\n With regards to compute storage usage, READ | WRITE means that you can have\n shader A that only writes into the texture and shader B that only reads\n from the texture and bind the same texture to either shader respectively.\n SIMULTANEOUS means that you can do reads and writes within the same shader\n or compute pass. It also implies that atomic ops can be used, since those\n are read-modify-write operations. If you use SIMULTANEOUS, you are\n responsible for avoiding data races, as there is no data synchronization\n within a compute pass. Note that SIMULTANEOUS usage is only supported by a\n limited number of texture formats.\n\n **Available Since:** This datatype is available since SDL 3.2.0.\n\n **See Also:** SDL_CreateGPUTexture\n"]
pub type SDL_GPUTextureUsageFlags = Uint32;
